${pagingTop} SELECT A.HOMEPAGE_ID, A.MEMBER_ID, A.MEMBER_NAME, A.PHONE, A.LINK_MEMBER_YN, A.add_date FROM CMS_MEMBER A WHERE 1=1
AND A.${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY A.ADD_DATE DESC ${pagingBottom}

