UPDATE CMS_MEMBER SET
MEMBER_PW = #{member_pw},
MEMBER_NAME = #{member_name}, homepage_id = #{homepage_id}, EMAIL = #{email}, ZIPCODE = #{zipcode}, ADDRESS1 = #{address1}, ADDRESS2 = #{address2}, PHONE = #{phone}, CELL_PHONE = #{cell_phone}, SMS_SERVICE_YN = #{sms_service_yn}, EMAIL_SERVICE_YN = #{email_service_yn} WHERE MEMBER_ID = #{member_id}

