SELECT MEMBER_ID, MEMBER_NAME FROM CMS_MEMBER WHERE MEMBER_ID NOT IN (select member_id from CMS_MEMBER_AUTH where AUTH_ID = #{search_auth})
AND HOMEPAGE_ID = #{homepage_id}
ORDER BY MEMBER_ID

SELECT MEMBER_ID, MEMBER_NAME, PHONE, CELL_PHONE, EMAIL FROM CMS_MEMBER WHERE MEMBER_ID IN (select member_id from CMS_MEMBER_AUTH where AUTH_ID = #{search_auth})
AND HOMEPAGE_ID = #{homepage_id}
ORDER BY MEMBER_ID

SELECT COUNT(*) FROM CMS_MEMBER WHERE MEMBER_ID IN (select member_id from CMS_MEMBER_AUTH where AUTH_ID = #{search_auth})
AND HOMEPAGE_ID = #{homepage_id}
ORDER BY MEMBER_ID

SELECT COUNT(*) FROM ( SELECT DISTINCT A.HOMEPAGE_ID, A.MEMBER_ID FROM CMS_MEMBER A
, WB_MEMBER_GROUP_SUBORD b, WB_MEMBER_GROUP c WHERE a.member_id = b.member_id AND b.member_group_idx = c.member_group_idx AND c.site_id = #{homepage_id}
AND A.${search_type} LIKE '%'||#{search_text}||'%'
